    def test_session_rename_dry_run(self, ds_name: str) -> None:
        ds_path, ds = _load_example_dataset(ds_name)

        # Find first session in first subject
        sub_dirs = sorted(
            d
            for d in ds_path.iterdir()
            if d.is_dir() and d.name.startswith("sub-")
        )
        ses_dir = None
        for s in sub_dirs:
